import{_ as e,o as t,c as n,ae as r}from"./chunks/framework.BD9pLfSD.js";const h=JSON.parse('{"title":" xB77 Demo Script: \\"The Sovereign Agent\\"","description":"","frontmatter":{},"headers":[],"relativePath":"docs/DEMO_SCRIPT.md","filePath":"docs/DEMO_SCRIPT.md"}'),a={name:"docs/DEMO_SCRIPT.md"};function i(l,o,s,c,g,d){return t(),n("div",null,[...o[0]||(o[0]=[r('<h1 id="-xb77-demo-script-the-sovereign-agent" tabindex="-1"> xB77 Demo Script: &quot;The Sovereign Agent&quot; <a class="header-anchor" href="#-xb77-demo-script-the-sovereign-agent" aria-label="Permalink to &quot; xB77 Demo Script: &quot;The Sovereign Agent&quot;&quot;">​</a></h1><p><strong>Target Duration:</strong> 3 Minutes <strong>Goal:</strong> Showcase Privacy, Compliance, and Autonomy.</p><h2 id="scene-0-setup-pre-record" tabindex="-1">Scene 0: Setup (Pre-Record) <a class="header-anchor" href="#scene-0-setup-pre-record" aria-label="Permalink to &quot;Scene 0: Setup (Pre-Record)&quot;">​</a></h2><ol><li><strong>Clean State:</strong> Delete <code>xb77_agent.db</code> (or <code>/tmp/...</code> if shared).</li><li><strong>Start Services:</strong><ul><li>Terminal 1: <code>bun run mcp/src/listener.ts</code></li><li>Terminal 2: <code>bun run mcp/src/http.ts</code> (Ensure <code>XB77_KEYPAIR_PATH</code> is set)</li><li>Terminal 3: <code>bun hub/index.ts</code></li></ul></li><li><strong>Open Browser:</strong> <code>http://localhost:7777</code>.</li><li><strong>Connect Agent:</strong> Go to &quot;Control Plane&quot;, click &quot;Refresh&quot;. Ensure Agent is <strong>Online</strong> and shows the <strong>Noir Badge</strong> (️ Identity Verified).</li></ol><hr><h2 id="scene-1-the-happy-path-standard-privacy" tabindex="-1">Scene 1: The &quot;Happy Path&quot; (Standard Privacy) <a class="header-anchor" href="#scene-1-the-happy-path-standard-privacy" aria-label="Permalink to &quot;Scene 1: The &quot;Happy Path&quot; (Standard Privacy)&quot;">​</a></h2><p><strong>Narrator:</strong> &quot;Agents need to spend money, but public blockchains leak their entire history. xB77 gives them privacy by default.&quot;</p><p><strong>Action:</strong></p><ol><li>Go to <strong>Terminal</strong> tab.</li><li>Click <strong>&quot;Buy Now&quot;</strong> on <strong>AWS Credits ($95)</strong>.</li><li><strong>Look at Feed:</strong><ul><li>See <code>🤖 Analyzing optimal route...</code></li><li>See <code>️ Standard Privacy...</code></li><li>See <code>Payment Confirmed</code>.</li></ul></li><li><strong>The Reveal:</strong> Click the <strong>Lock Icon ()</strong> on the feed item. <ul><li>Show that the amount was hidden (<code>*******</code>) and is now revealed locally.</li></ul></li></ol><h2 id="scene-2-the-compliance-guard-range-protocol" tabindex="-1">Scene 2: The Compliance Guard (Range Protocol) <a class="header-anchor" href="#scene-2-the-compliance-guard-range-protocol" aria-label="Permalink to &quot;Scene 2: The Compliance Guard (Range Protocol)&quot;">​</a></h2><p><strong>Narrator:</strong> &quot;But privacy can&#39;t be a tool for crime. We integrate Range Protocol to block sanctions in real-time.&quot;</p><p><strong>Action:</strong></p><ol><li>Click <strong>&quot;Buy Now&quot;</strong> on <strong>Dark Web Data ($499)</strong>.</li><li><strong>Look at Screen:</strong><ul><li><strong>RED ALERT MODAL</strong> appears immediately.</li><li>&quot;Risk Alert: Range Protocol&quot;.</li><li>&quot;Reason: Sanctioned Address&quot;.</li></ul></li><li>Click &quot;Acknowledge&quot;. Transaction cancelled.</li></ol><h2 id="scene-3-the-unicorn-feature-ghost-mode-governance" tabindex="-1">Scene 3: The Unicorn Feature (Ghost Mode &amp; Governance) <a class="header-anchor" href="#scene-3-the-unicorn-feature-ghost-mode-governance" aria-label="Permalink to &quot;Scene 3: The Unicorn Feature (Ghost Mode &amp; Governance)&quot;">​</a></h2><p><strong>Narrator:</strong> &quot;For high-value assets, the Agent switches to &#39;Ghost Mode&#39; and requests human authorization via our Shadow Governance Protocol.&quot;</p><p><strong>Action:</strong></p><ol><li>Click <strong>&quot;Buy Now&quot;</strong> on <strong>Quantum Farm ($50,000)</strong>.</li><li><strong>Alert:</strong> &quot;High Value Alert&quot;. Click <strong>OK</strong>.</li><li><strong>Feed:</strong> <code> GHOST MODE ACTIVATED</code>.</li><li><strong>Feed:</strong> <code>️ Blocked... Requesting approval...</code>.</li><li><strong>Switch Tab:</strong> Go to <strong>Governance</strong>.</li><li><strong>Action:</strong><ul><li>See &quot;Encrypted Intent&quot; (Lock icon).</li><li>Click <strong>&quot;Decrypt &amp; Inspect&quot;</strong>.</li><li>Read details: &quot;Asset Acquisition: Quantum Farm&quot;.</li><li>Click <strong>&quot;Sign &amp; Approve&quot;</strong>.</li></ul></li><li><strong>Switch Tab:</strong> Go back to <strong>Terminal</strong>.</li><li><strong>Wait 3s:</strong> Watch the feed automatically update. <ul><li><code>Agent Resuming...</code></li><li><code>Payment Confirmed</code>.</li></ul></li></ol><h2 id="scene-4-the-invoicing-accounting" tabindex="-1">Scene 4: The Invoicing (Accounting) <a class="header-anchor" href="#scene-4-the-invoicing-accounting" aria-label="Permalink to &quot;Scene 4: The Invoicing (Accounting)&quot;">​</a></h2><p><strong>Narrator:</strong> &quot;Finally, privacy shouldn&#39;t break accounting. We reconstruct tax-compliant invoices from encrypted on-chain metadata.&quot;</p><p><strong>Action:</strong></p><ol><li>Find the $50,000 transaction in the feed.</li><li>Click the <strong>&quot; Invoice&quot;</strong> button.</li><li><strong>Modal Opens:</strong> Show the detailed receipt with VAT breakdown.</li><li><strong>Narrator:</strong> &quot;The Sovereign Bank for the Machine Economy.&quot;</li></ol><p><strong>END RECORDING</strong></p>',22)])])}const p=e(a,[["render",i]]);export{h as __pageData,p as default};
